mapper.select:
select * from fp_metric_sample
where tenant_id = #{tenantId}
  and config_id = #{configId}
  and collected_at = (
      select max(collected_at) from fp_metric_sample
      where tenant_id = #{tenantId} and config_id = #{configId}
  )
order by case when series_type = 'AGGREGATE' then 0 else 1 end, instance asc

select * from fp_metric_sample
where tenant_id = #{tenantId}
  and metric_code = #{metricCode}
  and object_type = #{objectType}
  and object_id = #{objectId}
  and instance = #{instance}
  and series_type = #{seriesType}
order by collected_at desc
limit 1

select * from fp_metric_sample
where tenant_id = #{tenantId}
  and metric_code = #{metricCode}
  and object_type = #{objectType}
  and object_id = #{objectId}
  and instance = #{instance}
  and series_type = #{seriesType}
  and collected_at < #{beforeAt}
order by collected_at desc
limit 1

select * from fp_metric_sample
where tenant_id = #{tenantId}
  and metric_code = #{metricCode}
  and object_type = #{objectType}
  and object_id = #{objectId}
  and collected_at = (
      select max(collected_at) from fp_metric_sample
      where tenant_id = #{tenantId}
        and metric_code = #{metricCode}
        and object_type = #{objectType}
        and object_id = #{objectId}
  )
